css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0c0c14; color: white; }
.app { max-width: 900px; margin: 0 auto; padding: 30px 24px; }
header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 24px; flex-wrap: wrap; gap: 14px; }
header h1 { font-size: 26px; font-weight: 800; }
.search-box input { background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.1); border-radius: 12px; padding: 12px 18px; color: white; font-size: 14px; outline: none; width: 220px; }
.genre-row { display: flex; gap: 10px; margin-bottom: 24px; flex-wrap: wrap; }
.genre { background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); color: rgba(255,255,255,0.6); padding: 9px 18px; border-radius: 999px; font-size: 13px; font-weight: 700; cursor: pointer; }
.genre.active { background: rgba(239,68,68,0.15); color: #f87171; border-color: rgba(239,68,68,0.3); }
.movie-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(150px, 1fr)); gap: 18px; }
.movie-card { cursor: pointer; }
.movie-poster { aspect-ratio: 2/3; background: linear-gradient(150deg, #2d1b30, #0c0c14); border-radius: 12px; display: flex; align-items: center; justify-content: center; font-size: 50px; margin-bottom: 10px; position: relative; transition: 0.15s; }
.movie-card:hover .movie-poster { transform: scale(1.03); }
.rating-badge { position: absolute; top: 8px; right: 8px; background: rgba(0,0,0,0.6); backdrop-filter: blur(4px); padding: 4px 8px; border-radius: 8px; font-size: 11px; font-weight: 700; color: #facc15; }
.movie-card h3 { font-size: 14px; font-weight: 700; margin-bottom: 4px; }
.movie-card .sub { font-size: 12px; color: rgba(255,255,255,0.4); }
.modal { position: fixed; inset: 0; background: rgba(0,0,0,0.8); display: none; align-items: center; justify-content: center; padding: 20px; z-index: 10; }
.modal.show { display: flex; }
.modal-content { background: #15151f; border-radius: 20px; padding: 30px; max-width: 380px; width: 100%; text-align: center; }
.modal-poster { aspect-ratio: 2/3; max-height: 220px; background: linear-gradient(150deg, #2d1b30, #0c0c14); border-radius: 14px; display: flex; align-items: center; justify-content: center; font-size: 70px; margin: 0 auto 18px; }
.modal-content h2 { font-size: 22px; font-weight: 800; margin-bottom: 10px; }
.modal-meta { display: flex; gap: 10px; justify-content: center; margin-bottom: 16px; font-size: 12.5px; color: rgba(255,255,255,0.5); font-weight: 700; }
.modal-meta span { background: rgba(255,255,255,0.06); padding: 5px 12px; border-radius: 999px; }
.modal-content p { color: rgba(255,255,255,0.55); font-size: 13.5px; line-height: 1.7; margin-bottom: 22px; }
.close-btn { background: rgba(239,68,68,0.15); color: #f87171; border: none; padding: 12px 28px; border-radius: 999px; font-size: 14px; font-weight: 700; cursor: pointer; }

