const movies = [
  { title: 'Sonsuz Ufuk', genre: 'Bilim Kurgu', year: 2025, rating: 8.4, poster: '🚀', desc: 'Bir grup astronot, kara delik içinde kaybolmuş bir gemiyi kurtarmak için zamana karşı yarışıyor.' },
  { title: 'Kırık Aynalar', genre: 'Drama', year: 2024, rating: 7.9, poster: '🪞', desc: 'Bir ailenin geçmişle barışma sürecini anlatan duygusal bir hikaye.' },
  { title: 'Son Görev', genre: 'Aksiyon', year: 2026, rating: 8.1, poster: '💣', desc: 'Emekli bir ajan, son bir görev için sahaya geri dönüyor.' },
  { title: 'Gülmece Kulübü', genre: 'Komedi', year: 2025, rating: 7.2, poster: '🎭', desc: 'Bir grup arkadaşın stand-up komedi kulübü açma maceraları.' },
  { title: 'Yıldız Tozu', genre: 'Bilim Kurgu', year: 2023, rating: 8.7, poster: '🌌', desc: 'Uzak bir galakside geçen epik bir keşif yolculuğu.' },
  { title: 'Sessiz Sokaklar', genre: 'Drama', year: 2024, rating: 8.0, poster: '🏙️', desc: 'Büyük şehirde kaybolan bir gencin kendini bulma hikayesi.' },
  { title: 'Tehlikeli Oyun', genre: 'Aksiyon', year: 2025, rating: 7.6, poster: '🎯', desc: 'Bir kumarhanede başlayan soygun, beklenmedik bir takibe dönüşür.' },
  { title: 'Komşu Çetesi', genre: 'Komedi', year: 2026, rating: 6.9, poster: '🏠', desc: 'Birbirine hiç benzemeyen komşuların apartman savaşları.' }
];

let activeGenre = 'all';

function renderMovies() {
  const grid = document.getElementById('movieGrid');
  const query = document.getElementById('searchInput').value.toLowerCase();
  grid.innerHTML = '';
  movies
    .filter(m => activeGenre === 'all' || m.genre === activeGenre)
    .filter(m => m.title.toLowerCase().includes(query))
    .forEach(m => {
      const card = document.createElement('div');
      card.className = 'movie-card';
      card.innerHTML = `
        <div class="movie-poster">${m.poster}<span class="rating-badge">⭐ ${m.rating}</span></div>
        <h3>${m.title}</h3>
        <span class="sub">${m.genre} · ${m.year}</span>
      `;
      card.addEventListener('click', () => openModal(m));
      grid.appendChild(card);
    });
}

function filterGenre(btn, genre) {
  activeGenre = genre;
  document.querySelectorAll('.genre').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  renderMovies();
}

function filterMovies() {
  renderMovies();
}

function openModal(m) {
  document.getElementById('modalPoster').textContent = m.poster;
  document.getElementById('modalTitle').textContent = m.title;
  document.getElementById('modalGenre').textContent = m.genre;
  document.getElementById('modalYear').textContent = m.year;
  document.getElementById('modalRating').textContent = `⭐ ${m.rating}`;
  document.getElementById('modalDesc').textContent = m.desc;
  document.getElementById('modal').classList.add('show');
}

function closeModal(e) {
  if (e.target.id === 'modal' || e.target.classList.contains('close-btn')) {
    document.getElementById('modal').classList.remove('show');
  }
}

renderMovies();
